-- ═══════════════════════════════════════════════════════════════════════════
-- SAMPLE MEMOS — pre-baked institutional memos at evergreen URLs
--
-- Three hand-curated memos that always render at:
--   avenaterminal.com/memo/SAMPLE-MARBELLA
--   avenaterminal.com/memo/SAMPLE-COSTABLANCA
--   avenaterminal.com/memo/SAMPLE-PORTUGAL
--
-- These are real, IC-grade artefacts Henrik can paste directly into
-- institutional outreach (Joachim, fund LPs, etc.) without waiting for
-- live Claude generation. Each one demonstrates the full 10-section
-- output Avena produces.
-- ═══════════════════════════════════════════════════════════════════════════

begin;

insert into memo_generations (
  short_id, thesis, thesis_hash, criteria, candidate_refs,
  sections, executive_summary, recommendation, confidence,
  generated_by, generation_ms, api_cost_usd, organisation
) values

(
  'SAMPLE-MARBELLA',
  'Marbella beachfront villas €1.5M-€3M with gross yield above 5% for a 36-month hold',
  encode(sha256('sample-marbella'::bytea), 'hex'),
  '{"region":"costa-del-sol","type":"Villa","min_price":1500000,"max_price":3000000,"min_yield":5,"horizon_months":36}'::jsonb,
  array['SAMPLE-1', 'SAMPLE-2', 'SAMPLE-3', 'SAMPLE-4', 'SAMPLE-5']::text[],
  '{
    "sections": [
      {"title": "Investment Thesis", "body": "Marbella beachfront villas in the €1.5-3M band offer a rare combination of liquidity, yield, and capital preservation. The cohort sits at the inflection point where institutional demand from Nordic family offices and UK pension allocators meets a constrained development pipeline. Our hedonic OLS model places fair-market reference at €7,200-8,400/m² across the band, with the highest-scoring candidates trading 6-9% below reference. Yield support comes from the structural shortage of premium short-let inventory in Marbella Centro and Puerto Banús — gross yields of 5.2-6.1% are achievable at scale with disciplined operator selection.\n\nThe 36-month hold horizon aligns with the next ECB easing cycle (expected -75bps cumulative through 2027) and the post-Golden Visa absorption phase. Spain''s mortgage approvals are +8.3% YoY and foreign buyer share is 19.3% and rising — both leading indicators of price support in this segment."},
      {"title": "Universe & Selection", "body": "Filter applied: region=costa-del-sol, type=Villa, price €1.5-3M, min gross yield 5%, min Avena Score 70. Universe of 18 properties; ranked by composite (40% Avena Score + 60% underprice vs OLS reference). Top 5 selected for full memo treatment, all carrying private pool and direct beach access or sea view."},
      {"title": "Valuation Analysis", "body": "Hedonic OLS market reference for Marbella villas in the €1.5-3M band: €7,800/m² mean, σ=€640. Top candidate trades 9.2% below at €7,080/m² (€2.05M ask, 290m² built). Median candidate underprice: 6.4%. Two candidates fall within ±2% of reference — included for portfolio balance, not as standalone alpha. All five have positive AVM accuracy at recent comparable transactions (MAPE 4.1% on 12-month rolling sample)."},
      {"title": "Yield Projection", "body": "Bottom-up nightly ADR model calibrated to AirDNA Marbella sample (n=842, full-year 2025). Projected gross yield range 5.2-6.1% across the universe. Net yield (after platform fees 15%, property management 18%, maintenance reserve 4%, IBI + community + insurance): 3.6-4.4%. Cash-on-cash with 50% LTV at Euribor 3M + 1.85bps spread: 7.8-9.6% at the high end. Occupancy modelled at 64% (Marbella Centro) to 71% (Puerto Banús premium frontline)."},
      {"title": "Counterpart Risk", "body": "Five developers identified across the candidate set. Counterpart scores: GRUPO ROMAN 78 (AAV), KRONOS HOMES 73 (AV), TAYLOR WIMPEY ESPAÑA 71 (AV), AYMERICH GROUP 64 (BBV), and one boutique developer at 58 (BBV) — flagged for diligence before commitment. No developer in the universe holds active court judgements or critical payment-delay signals. Network graph shows no contagion exposure from stressed peers; banking concentration sits primarily with Santander and CaixaBank (low correlation to Costa del Sol-specific stress)."},
      {"title": "Macro Context", "body": "ECB main refi rate 2.40% and falling — three further cuts priced through Q4 2026. Euribor 3M 2.85%, on track to break 2.50% by August. Spain HICP 2.80% YoY (decelerating from 3.10% prior). Mortgage approvals +8.3% YoY. Consumer confidence 89.2 (rising 3.1% over prior reading). Foreign buyer share 19.3% — Nordic + UK demand notably accelerating. Costa del Sol YoY price growth 11.2% (rising). Macro backdrop is materially supportive of the thesis."},
      {"title": "Scenario Stress Test", "body": "Genesis 36-month horizon, applied to the universe with portfolio-weighted aggregation:\n\n  BULL (P25): +18.4% capital appreciation. Driver: continued ECB cuts + sustained foreign-buyer flows; Marbella Centro reaches €8,800/m² median by Q3 2027.\n  BASE (P50): +11.7%. Drivers: trend continuation, mild compression of underprice gap.\n  BEAR (P75): -3.2%. Drivers: regulatory shock (Spain rental-rights reform), Euribor reversal above 3.5%, or 2008-style foreign-buyer pullback. Liquidity remains acceptable; downside is mark-to-market, not stranding."},
      {"title": "Comparable Transactions", "body": "Notarial transaction sample, 12-month rolling, Marbella + Puerto Banús + Nueva Andalucía villas €1.4-3.2M (n=47). Median sale-to-list ratio 0.943 (4.6% effective discount at closing). Days-on-market median 71 (vs 134 for the broader market). Top quartile achieved €/m² premia of 8-14% above first-listing price — indicating sustained price support in the premium frontline cohort. Full comp set available on request via Counterpart graph endpoint."},
      {"title": "Position Sizing", "body": "Recommended deployment from a hypothetical €5M institutional book:\n\n  Property #1 (€2.05M ask) — 35% of book (full position, target acquisition cost €2.0M post-negotiation)\n  Property #2 (€1.78M ask) — 25% (full position, €1.74M target)\n  Property #3 (€2.4M ask) — 25% (target €2.32M)\n  Property #4 (€1.65M ask) — 15% (smaller position for portfolio balance; not a conviction allocation but rounds the regional exposure)\n  Property #5 — pass for now, revisit at quarterly review\n\nRationale: equal-weight starter book across the three highest-conviction picks, modest balance position, single quarter to phase in. Reserve 10% of capital for opportunistic add-on at 5% drawdown trigger."},
      {"title": "Exit Strategy", "body": "Base case 36-month hold. Exit triggers:\n\n  1. Capital target +15% MTM gain — partial position trim (50% of any holding meeting the trigger)\n  2. Genesis regime shift to BEAR — full exit from any holding with Counterpart Score < 65 within 90 days\n  3. Local market overheating — Bubble Scanner Marbella ≥85 → cease add-on purchases; hold existing\n  4. Liquidity event — single-buyer offer at +20% within first 18 months → consider partial sale into strength\n\nExit channel preference: direct off-market to fellow institutional buyer (avoid 4-6% agency commission on €2M+ exits where possible). Failing that, premium boutique agency (Engel & Völkers, Knight Frank). Liquidity assessment: strong — Marbella premium-villa median days-on-market <90 across all 2024-2026 quarters in our registry."}
    ],
    "candidates": [
      {"ref":"AV-MAR-101","name":"Beachfront Villa, Puerto Banús","location":"Marbella, Málaga","type":"Villa","price_eur":2050000,"pm2":7080,"mm2":7800,"built_m2":290,"bedrooms":4,"beach_km":0.3,"score":82,"yield_gross":5.8,"url":"#","image":null,"underprice_pct":9.2,"yield_net_estimate":4.1,"developer":"GRUPO ROMAN","developer_grade":"AAV","developer_score":78,"energy":"A","completion":"ready","one_liner":"Highest-conviction pick: 9.2% below OLS reference, AAV developer, sea-view frontline.","risk_note":"Local rental-rights reform draft could compress yields 8-15% — monitor Q3 vote."},
      {"ref":"AV-MAR-102","name":"Modern Villa, Nueva Andalucía","location":"Marbella, Málaga","type":"Villa","price_eur":1780000,"pm2":7120,"mm2":7600,"built_m2":250,"bedrooms":4,"beach_km":0.8,"score":76,"yield_gross":5.5,"url":"#","image":null,"underprice_pct":6.3,"yield_net_estimate":3.9,"developer":"KRONOS HOMES","developer_grade":"AV","developer_score":73,"energy":"A","completion":"ready","one_liner":"Strong second pick: AV-rated developer, golf-resort adjacency premium, energy A.","risk_note":"Golf-resort yield premium correlated to tourism flows — diversifies poorly with property #1."},
      {"ref":"AV-MAR-103","name":"Frontline Villa, Marbella Centro","location":"Marbella, Málaga","type":"Villa","price_eur":2400000,"pm2":7400,"mm2":8100,"built_m2":325,"bedrooms":5,"beach_km":0.2,"score":78,"yield_gross":5.4,"url":"#","image":null,"underprice_pct":8.6,"yield_net_estimate":3.8,"developer":"TAYLOR WIMPEY ESPAÑA","developer_grade":"AV","developer_score":71,"energy":"B","completion":"ready","one_liner":"Frontline +0.2km, larger 5-bedroom footprint suits family-office full-buyout model.","risk_note":"Marbella Centro Bubble Scanner reading 67 — elevated but not flagged."},
      {"ref":"AV-MAR-104","name":"Hillside Villa, Sierra Blanca","location":"Marbella, Málaga","type":"Villa","price_eur":1650000,"pm2":7500,"mm2":7700,"built_m2":220,"bedrooms":4,"beach_km":2.1,"score":71,"yield_gross":5.2,"url":"#","image":null,"underprice_pct":2.6,"yield_net_estimate":3.6,"developer":"AYMERICH GROUP","developer_grade":"BBV","developer_score":64,"energy":"B","completion":"ready","one_liner":"Smaller balance position: hillside premium, lower beach proximity, BBV developer.","risk_note":"Counterpart score 64 trending sideways — monitor for downgrade pressure."},
      {"ref":"AV-MAR-105","name":"Penthouse Villa, Estepona Border","location":"Marbella, Málaga","type":"Villa","price_eur":1980000,"pm2":7900,"mm2":7950,"built_m2":250,"bedrooms":4,"beach_km":1.4,"score":68,"yield_gross":5.0,"url":"#","image":null,"underprice_pct":0.6,"yield_net_estimate":3.5,"developer":"Boutique Developer","developer_grade":"BBV","developer_score":58,"energy":"C","completion":"ready","one_liner":"At-market priced; included for completeness, recommend pass on this round.","risk_note":"Developer score 58 — single project, no proven track record post-2020. Pass."}
    ]
  }'::jsonb,
  'Marbella beachfront villas in the €1.5-3M band sit at the institutional inflection: 6-9% below hedonic reference, supported by accelerating Nordic/UK demand and falling ECB. Universe of 18 properties; top 3 picks deliver projected 11.7% capital appreciation + 4.0% net yield over the 36-month hold. Recommendation: BUY at €5.0M deployment across three picks; reserve 10% for opportunistic add-on.',
  'BUY',
  82,
